import sys
n,m = map(int,sys.stdin.readline().split())
edge = [[] for _ in range(n+1)]
for i in range(m):
    u,v = map(int,sys.stdin.readline().split())
    edge[u].append(v)
    edge[v].append(u)

def dfs(u,p):
    for v in edge[u]:
        if v != p:
            if dfs(v,u):
                return 1
    return 0

if dfs(1,-1):
    print("1")
    print(n//2+1,n)
    for i in range(n//2+1,n+1):
        print(i,end = " ")
else:
    print("2")
    print(n)
    print(1,n,1)
    for i in range(2,n+1):
        print(i,end = " ")
